// Secure-RNG pool for the native (flutter_js) engine. Installed BEFORE the engine bundle so that
// `new ProtocolEngine()` (which mints a per-session cover key) finds `crypto.getRandomValues`, which
// JavaScriptCore otherwise lacks. The pool bytes are OS CSPRNG, generated by Dart `Random.secure()`
// and passed in as base64; this file ONLY decodes and serves them — there is no PRNG here (every byte
// is OS entropy; Constitution I/II).
//
// `refill` (optional): a SYNCHRONOUS `function(n) -> base64` returning n fresh OS-CSPRNG bytes. When
// provided (production: a flutter_js `sendMessage` bridge to Dart `Random.secure()`), the pool is
// effectively UNBOUNDED — `getRandomValues` tops it up on demand. When absent (the dev/no-bridge
// fallback), the pool is finite and exhausting it throws a DISTINCT `ENTROPY_POOL_EXHAUSTED`.
//
// Single source of truth: `engine_factory_io.dart` loads this exact file at runtime, and
// `protocol-core-js/e2e/rng-pool.cjs` tests the decoder + serve/refill/exhaust behaviour in Node.
globalThis.__installSecureRandomPool = function (b64, refill) {
  var T = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  var lut = {};
  for (var i = 0; i < T.length; i++) lut[T.charAt(i)] = i;
  function decode(s) {
    var clean = s.replace(/=+$/, ''); // tolerate optional padding (atob is absent in JSC/QuickJS)
    var out = new Uint8Array((clean.length * 6) >> 3);
    var acc = 0, bits = 0, o = 0;
    for (var j = 0; j < clean.length; j++) {
      acc = (acc << 6) | lut[clean.charAt(j)];
      bits += 6;
      if (bits >= 8) { bits -= 8; out[o++] = (acc >> bits) & 0xff; }
    }
    return out;
  }

  var pool = decode(b64);
  var off = 0;
  globalThis.crypto = {
    getRandomValues: function (arr) {
      var n = arr.length;
      if (off + n > pool.length) {
        if (!refill) throw new Error('ENTROPY_POOL_EXHAUSTED');
        // Top up: keep the unconsumed tail, append a fresh OS-entropy chunk (>= what we still need).
        var rem = pool.length - off;
        var fresh = decode(refill(Math.max(n - rem, 32768)));
        if (fresh.length < n - rem) throw new Error('ENTROPY_POOL_EXHAUSTED'); // refill under-delivered
        var np = new Uint8Array(rem + fresh.length);
        np.set(pool.subarray(off), 0);
        np.set(fresh, rem);
        pool = np;
        off = 0;
      }
      for (var k = 0; k < n; k++) arr[k] = pool[off + k];
      off += n;
      return arr;
    },
  };
  return pool.length;
};
